% -------------------------------------------------------------------------
% PL Greenness Figure Reproduction Script
% -------------------------------------------------------------------------
% Recreates the manuscript figures for "Optimal light use strategy explains
% seasonal vegetation greenness dynamics and trends". The workflow contrasts
% PL-model greenness with satellite benchmarks, flux sites, and TRENDY
% ensembles. Run inside code/ with the packaged data/ assets available.
% -------------------------------------------------------------------------
% The script expects the data/ directory one level up to contain all GeoTIFF
% stacks and MAT files referenced below. Figure assets are written to figure/.
% -------------------------------------------------------------------------
%%
%% Figure 1 – Global seasonality of greenness versus potential production
% Builds the three panel map comparing MODIS fAPAR and PL-derived A0
% seasonality plus the accompanying latitude band summary curve.
% Load the static mask and add helper utilities required by custom plotting
% and statistical routines used across all figures.
roi_single_year = geotiffread("../data/roi_global_05d.tif"); %#ok<*GTRED> 
addpath("./utility/");

% Shared plotting and analysis settings
timestep = 30;                    % Approximate number of days per composited step
font_size = 11;                   % Base font size for shared colorbars
options.fontsize = 14;            % Map annotation font size
options.text_position_middle = [-56,-46];
options.text_position_right = [-158,-46];

% Load monthly (MODIS, PL model, TRENDY) and weekly (A0) stacks used to
% summarize greenness and potential production.
fapar_obs_mon = geotiffread("../data/fapar_global_modis_05d.tif");
fapar_sim_mon = geotiffread("../data/fapar_global_plmodel_05d.tif");
raster_trendy_12mon = geotiffread("../data/fapar_trendy_plmodel_05d.tif");
A0_gC_weekly = geotiffread("../data/a0_global_plmodel_05d.tif");

% Collapse each stack into seasonality diagnostics using the shared TS()
% helper. Timing outputs are retained for completeness although not used
% directly in the figure panels.
[seasonalityA0,timingA0,timingA0Cos] = TS(A0_gC_weekly,'timestep',timestep);
[seasonalityPL,timingPL,timingPLCos] = TS(fapar_sim_mon,'timestep',timestep);
[seasonalityMod,timingMod,timingModCos] = TS(fapar_obs_mon,'timestep',timestep);
[seasonalityTrendy,timingTrendy,timingTrendyCos] = TS(raster_trendy_12mon,'timestep',timestep);

% Precompute color palettes and shared temporal metadata
cb_paired = cbrewer_hint("qual", "Paired", 12);
cb_set1 = cbrewer_hint("qual","Set1",9);
cb_set2 = cbrewer_hint("qual","Set2",8);
cb_pastel2 = cbrewer_hint('qual','Pastel2',9);

YearBgn = 2000;
YearEnd = 2019;
YearNum = numel(YearBgn:YearEnd);

options.range_value = [0, 0.9];
options.text_position = [-160,-45];
roi_12mon = repmat(roi_single_year, [1,1,12]);

% All figures export to the shared figure/ folder
path_figure_output = '../figure/';
%%
% Create the composite layout with two rows of maps and a shared side panel
fig = figure('Color', [1 1 1]); %[output:6aa322ae]
fig.Position(3) = fig.Position(3)*1.12; %[output:6aa322ae]
fig.Position(2) = fig.Position(2)*0.6; %[output:6aa322ae]
fig.Position(4) = fig.Position(4)*1.08; %[output:6aa322ae]

left_width = 10;
right_width = 4;
tl = tiledlayout(2,left_width + right_width,"TileSpacing","tight"); %[output:6aa322ae]
tl.Padding = "compact"; % Match legacy spacing so shared colorbars align with map width %[output:6aa322ae]

% Panel (a): MODIS fAPAR seasonality map
nexttile(1, [1,left_width]); %[output:6aa322ae]
data_obs = seasonalityMod;
data_obs(~(roi_single_year)) = nan;
geoshow_global(data_obs,"logic_show_yticks","true","logic_show_xticks","false"); %[output:6aa322ae]
set(gca, 'Clim', [0, 1.0]); %[output:6aa322ae]
set(gca,'FontSize',options.fontsize-3); %[output:6aa322ae]

% Panel (b): PL modeled A0 seasonality map
nexttile(1+(left_width+right_width), [1,left_width]); %[output:6aa322ae]
data_sim = seasonalityA0;
data_sim(~(roi_single_year)) = nan;
geoshow_global(data_sim,"logic_show_yticks","true","logic_show_xticks","false"); %[output:6aa322ae]
set(gca, 'Clim', [0, 1]); %[output:6aa322ae]
set(gca,'FontSize',options.fontsize-3); %[output:6aa322ae]

cb_map = slanCM(56, 12); colormap(cb_map(2:(end-1),:)); %[output:6aa322ae]
cb = colorbar(gca, 'Location', 'southoutside','FontSize',font_size);% cbarrow %[output:6aa322ae]
% cb.Layout.Tile = 'south';
% cb.Layout.TileSpan = [1 left_width]; % Keep bar centered beneath the paired map tiles

% Panel (c): Latitude band summary of both seasonality metrics
nexttile(1+left_width, [2,right_width]); %[output:6aa322ae]
plot_lat_bands(cat(3,data_obs,data_sim), "logic_plot",true, "ylabel",'',"fontsize",13,'fontbold','normal','str_legend',["\it{f}\rm_{APAR}","\it{A}\rm_{0}\rm"],'line_color',cb_paired([2,6],:)); %[output:6aa322ae]
set(gca,'FontSize',options.fontsize-3); %[output:6aa322ae]
yticks(0:0.4:1); %[output:6aa322ae]

exportgraphics(fig, fullfile(path_figure_output, 'Seasonality_Pattern_A0.png'),"Resolution",600); %[output:6aa322ae]
%%
%% Figure 2 – Flux site synchrony between fAPAR and potential production
% Visualizes how observed greenness co-varies with A0 across eddy covariance
% biomes using box and jittered scatter summaries, plus a map of correlation
% strength for the tower network.
param_table = readtable("../data/FluxInformation.csv"); %[output:9987e4bf] %[output:8ffc0a3d]
fig_flux = figure('Color',[1 1 1]); %[output:1ef0d128]
fig_flux.Position(4) = fig_flux.Position(4)*0.7; %[output:1ef0d128]
colororder(fig_flux, cb_paired([2,1,6],:));
cb_violin = [cb_paired(2,:); cb_paired(1,:)];

% Order categories to match manuscript grouping
param_table_target = ["EBF","SAV","WSA","OSH","CSH","GRA","WET","ENF","MF","DBF"];
param_table.categorial = categorical(param_table.IGBPClass, param_table_target, param_table_target);

% Use a single tile layout to overlay box charts and jittered points
nexttile; %[output:1ef0d128]
hold on; %[output:1ef0d128]
index_grp = cat(1, repmat(categorical("P model"), height(param_table),1));
boxchart(repmat(param_table.categorial, [1,1]), [param_table.r_a0_fapar], 'GroupByColor',index_grp,"MarkerStyle","none","Notch","off","MarkerSize",12,"JitterOutliers","off"); %[output:1ef0d128]
ylabel('\it{r}','FontSize',options.fontsize); %[output:1ef0d128]
ylim([0,1]); %[output:1ef0d128]
set(gca, 'fontsize', options.fontsize-2); %[output:1ef0d128]
box on; %[output:1ef0d128]
[found, idx] = ismember(param_table.categorial, categorical(param_table_target));
[~, sortorder] = sort(idx);
newT = param_table.categorial(sortorder,:);
scatter(newT,param_table.r_a0_fapar(sortorder,:),'filled','MarkerFaceAlpha',0.6,'jitter','on','jitterAmount',0.15); %[output:1ef0d128]

if any(~found)
    error('Site not on approved list, first at row %d', find(~found,1));
end

nexttile; %[output:1ef0d128]
% Overlay individual site correlations to show spread within each biome
violinplot(param_table.r_a0_fapar(sortorder,:), newT,'QuartileStyle','boxplot','ViolinColor',cb_violin(1,:),'MarkerSize',12,'ShowWhiskers',false,'ShowBox',true,'ViolinAlpha',0,'EdgeColor',cb_violin(2,:),'ShowData',false,'ShowMean',false); %[output:1ef0d128]
ylabel('\it{r}','FontSize',options.fontsize); %[output:1ef0d128]
hold off; %[output:1ef0d128]
box on; %[output:1ef0d128]
% grid on;
xlim([0.5, numel(param_table_target)+0.5]); %[output:1ef0d128]
ylim([0, 1]); %[output:1ef0d128]
set(gca, 'fontsize', options.fontsize-2); %[output:1ef0d128]
exportgraphics(fig_flux, fullfile(path_figure_output, 'FluxSynchrony_Box.png'),"Resolution",600); %[output:1ef0d128]
% Companion map: spatial distribution of the site correlations
fig_flux_map = figure('Color',[1 1 1]); %[output:35ecc7f0]
ax = geoaxes(fig_flux_map); %[output:35ecc7f0]
ax.Scalebar.Visible = 'off'; %[output:35ecc7f0]
geoscatter(double(param_table.Lat), double(param_table.Lon), 20, param_table.('r_a0_fapar'),"filled"); %[output:35ecc7f0]
ax.LongitudeLabel.String = 'Longitude (°)'; %[output:35ecc7f0]
ax.LatitudeLabel.String = 'Latitude (°)'; %[output:35ecc7f0]
geolimits(ax,[-60, 70],[-175, 175]); %[output:35ecc7f0]

ax.FontSize = options.fontsize-3; %[output:35ecc7f0]
cb = colorbar('Location','southoutside','FontSize',font_size); %[output:35ecc7f0]
colormap(cbrewer_hint("seq","GnBu",8)); %[output:35ecc7f0]
ax.CLim = [0.1,0.9]; %[output:35ecc7f0]
warning off;
cbarrow; %[output:35ecc7f0]
warning on;
geobasemap("grayland") %[output:35ecc7f0]
exportgraphics(fig_flux_map, fullfile(path_figure_output, 'FluxSynchrony_Map.png'),"Resolution",600); %[output:35ecc7f0]
%%
%% Figure 3 – Global multi year fAPAR comparison
% Provides the paired PL versus MODIS climatology maps and a latitude band
% comparison for the averaging period. A dedicated scatter plot follows in
% the supplementary panel.
fig = figure('Color', [1 1 1]); %[output:0e50e5c8]
fig.Position(3) = fig.Position(3)*1.1; %[output:0e50e5c8]
fig.Position(4) = fig.Position(4)*1.08; %[output:0e50e5c8]
tl_fig3 = tiledlayout(2,3,"TileSpacing","tight"); %[output:0e50e5c8]
tl_fig3.Padding = "compact"; % Preserve compact margins across MATLAB releases %[output:0e50e5c8]

% Panel (a): PL model climatology
nexttile(1, [1,2]); %[output:0e50e5c8]
fapar_predicted_min_matrix_disp = mean(fapar_sim_mon, 3, "omitnan");
fapar_predicted_min_matrix_disp(~roi_single_year) = nan;
geoshow_global(fapar_predicted_min_matrix_disp,"logic_show_yticks","true","logic_show_xticks","false"); %[output:0e50e5c8]
set(gca, 'Clim', options.range_value); %[output:0e50e5c8]
text(options.text_position_middle(1)+34, options.text_position_middle(2)-2, 'PL model','FontSize',options.fontsize); %[output:0e50e5c8]
set(gca,'FontSize',options.fontsize); %[output:0e50e5c8]

% Panel (b): MODIS climatology
nexttile(4, [1,2]); %[output:0e50e5c8]
data_disp = mean(fapar_obs_mon, 3, "omitnan");
data_disp(data_disp==0)=nan;
data_disp(~roi_single_year) = nan;
geoshow_global(data_disp,"logic_show_yticks","true","logic_show_xticks","false"); %[output:0e50e5c8]
set(gca, 'Clim', options.range_value); %[output:0e50e5c8]

cb = colorbar(gca, 'southoutside','FontSize',font_size);% cbarrow %[output:0e50e5c8]
% cb.Layout.Tile = 'south';
% cb.Layout.TileSpan = [1 2];
% cbarrow('right');
text(options.text_position_middle(1)+44, options.text_position_middle(2)-2, 'MODIS','FontSize',options.fontsize); %[output:0e50e5c8]
set(gca,'FontSize',options.fontsize); %[output:0e50e5c8]

cb_map = slanCM(56, 10); colormap(cb_map(1:(end-1),:)); %[output:0e50e5c8]

% Panel (c): Compare zonal means across products
nexttile(3, [2,1]); %[output:0e50e5c8]
plot_lat_bands(cat(3,fapar_predicted_min_matrix_disp, data_disp), "logic_plot",true, "ylabel",'',"fontsize",13,'fontbold','normal','str_legend',["PL model","MODIS"],'line_color',cb_set1(1:4,:)); %[output:0e50e5c8]
exportgraphics(fig, fullfile(path_figure_output, 'spatial_compare.png'),"Resolution",600); %[output:0e50e5c8]
%% Figure 3 – Pixel-wise density comparison (panel a)
% Uses a log density scatter to contrast monthly PL and MODIS fAPAR across
% all valid grid cells.
fig_density = figure('Color',[1 1 1]); %[output:11d3e929]
set(gca,'fontsize',options.fontsize-3); %[output:11d3e929]

roi_resample = logical(roi_12mon);
scatter_plot_data_comparison(fapar_sim_mon(roi_resample), fapar_obs_mon(roi_resample), "PlotDisp","off","PlotDensity","on","PlotConf","off","AxisLim",[0,1.1,0,1.1],"AxisEqual","on","StatisLocation","northwest","StatisDispItem","r2+rmse+equ","StatisCrossZero","off", "RobustOpts","off","FontSize",options.fontsize-2); %[output:11d3e929]
xlabel('PL model Monthly \it{f}\rm_{APAR}') %[output:11d3e929]
ylabel('MODIS Monthly \it{f}\rm_{APAR}') %[output:11d3e929]
grid off; %[output:11d3e929]
set(gca,'ColorScale','log'); %[output:11d3e929]
set(gca,'fontsize',options.fontsize); %[output:11d3e929]
text(0.88, 0.7, "Density","FontSize",options.fontsize-1.5); %[output:11d3e929]
cb = colorbar(gca, 'eastoutside','Units','normalized','FontSize',font_size); %[output:11d3e929]
cb.Position = [0.65, 0.18, 0.02, 0.42]; %[output:11d3e929]
cb.Ticks = [10^-2, 10^-1, 1, 10]; %[output:11d3e929]
set(gca, 'clim', [cb.Ticks(1), cb.Ticks(end)]); %[output:11d3e929]
cb.TickLabels = {'1', '10', '100', '1000'}; %[output:11d3e929]
cb_map = slanCM(61, 30); cb_map = flipud(cb_map(1:(end-5),:)); colormap(cb_map); % classic color viridis %[output:11d3e929]
exportgraphics(fig_density, fullfile(path_figure_output, 'spatial_compare_density.png'),"Resolution",600); %[output:11d3e929]
%%
%% Figure 4 – Seasonal cycle comparison across MODIS, TRENDY, and PL
% Shows the spatial seasonality concentration for MODIS, TRENDY ensemble,
% and PL simulations in a vertical stack with matched color scaling.
xtext = -56;
ytext = -44;
sizetext = 13;

fig = figure('Color', [1 1 1]); %[output:3ea26371]
fig.Position(3) = fig.Position(3)*0.7; %[output:3ea26371]
fig.Position(2) = fig.Position(2)*0.6; %[output:3ea26371]
fig.Position(4) = fig.Position(4)*1.2; %[output:3ea26371]

tl_fig4 = tiledlayout(3,1,"TileSpacing","tight"); %[output:3ea26371]
tl_fig4.Padding = "compact"; %[output:3ea26371]

% Panel (a): TRENDY ensemble seasonality magnitude
nexttile(1, [1,1]); %[output:3ea26371]
data_sim = seasonalityTrendy;
data_sim(~(roi_single_year)) = nan;
geoshow_global(data_sim,"logic_show_ticks","false"); %[output:3ea26371]
set(gca, 'Clim', [0, 1]); %[output:3ea26371]
text(xtext, ytext, ['TRENDY ', 'Seasonality'],'FontSize',sizetext); %[output:3ea26371]
set(gca,'FontSize',options.fontsize); %[output:3ea26371]

% Panel (b): MODIS benchmark seasonality magnitude
nexttile(2, [1,1]); %[output:3ea26371]
data_obs = seasonalityMod;
data_obs(~(roi_single_year)) = nan;
geoshow_global(data_obs,"logic_show_ticks","false"); %[output:3ea26371]
set(gca, 'Clim', [0, 1.0]); %[output:3ea26371]
text(xtext, ytext, ['\it{f}\rm_{APAR} ', 'Seasonality'],'FontSize',sizetext); %[output:3ea26371]
set(gca,'FontSize',options.fontsize); %[output:3ea26371]

% Panel (c): PL model seasonality magnitude
nexttile(3, [1,1]); %[output:3ea26371]
data_sim = seasonalityPL;
data_sim(~(roi_single_year)) = nan;
geoshow_global(data_sim,"logic_show_ticks","false"); %[output:3ea26371]
set(gca, 'Clim', [0, 1]); %[output:3ea26371]
text(xtext, ytext, ['PL model ', 'Seasonality'],'FontSize',sizetext); %[output:3ea26371]
set(gca,'FontSize',options.fontsize); %[output:3ea26371]

cb_map = slanCM(56, 12); colormap(cb_map(2:(end-1),:)); %[output:3ea26371]
font_size = max(font_size, 13);

cb = colorbar(gca, 'southoutside','FontSize',font_size);% cbarrow %[output:3ea26371]
cb.Layout.Tile = 'south'; %[output:3ea26371]
% cb.Position(4) = cb.Position(4)*0.4;
% cbarrow('right');
exportgraphics(fig, fullfile(path_figure_output, 'Seasonality_Pattern.png'),"Resolution",600); %[output:3ea26371]

load(fullfile('../data/', ['trendy_param_output','.mat']))
load(fullfile('../data/', ['trendy_data_output','.mat']))

num = size(param_model.name,1);
% show the comparison of the trendy models
param_model.name{num+1} = 'PLmodel';
param_model.r2_fit(num+1) = 0.81;
param_model.r2_season(num+1) = 0.86;
param_model.rmse_fit(num+1) = 0.13;

[~, ind_sort] = sort(param_model.r2_fit, 1, "ascend");
X = categorical(param_model.name(ind_sort));
X = reordercats(X,param_model.name(ind_sort));

fig_trendy = figure('Color',[1 1 1]); %[output:387e4069]
colororder(cat(1, [0.1,0.1,0.1], cb_set2(3,:)))

yyaxis left %[output:387e4069]
fig_bar2 = bar(X, cat(2,param_model.rmse_fit(ind_sort),zeros(size(param_model.rmse_fit))), 'FaceColor','flat',"LineWidth",0.6,"BarWidth",1.0); %[output:387e4069]
fig_bar2(1).CData(1:num,:) = repmat([0.9,0.9,0.9], [num,1]); %[output:387e4069]
fig_bar2(1).CData(num+1,:) = [0.9,0.9,0.9]; %[output:387e4069]

yyaxis right %[output:387e4069]
fig_bar = bar(X, cat(2,zeros(size(param_model.r2_fit)),param_model.r2_fit(ind_sort)),'FaceColor','flat',"LineWidth",0.6,"BarWidth",1.0); %[output:387e4069]
fig_bar(2).CData(1:num,:) = repmat(cb_set2(3,:), [num,1]); %[output:387e4069]
fig_bar(2).CData(num+1,:) = cb_set2(3,:); %[output:387e4069]
ylim([0,1]) %[output:387e4069]
set(gca, 'fontsize', options.fontsize-2) %[output:387e4069]
exportgraphics(fig_trendy, fullfile(path_figure_output, 'Trendy_Performance.png'),"Resolution",600); %[output:387e4069]
fprintf('Mean R2 = %.2f ± %.2f', mean(param_model.r2_fit(1:end-1)), std(param_model.r2_fit(1:end-1))) %[output:681c7177]
fprintf('Mean RMSE = %.2f ± %.2f', mean(param_model.rmse_fit(1:end-1)), std(param_model.rmse_fit(1:end-1))) %[output:49b8ac5b]
fprintf('Mean seasonality = %.2f ± %.2f', mean(param_model.r2_season(1:end-1)), std(param_model.r2_season(1:end-1))) %[output:89e9da6a]
%%
%% Figure 5 – Global greenness trends and driver attribution
% Computes long-term fAPAR trends for MODIS and PL simulations and prepares
% driver attribution layers for the PL experiments.
[fapar_obs_multi,R] = geotiffread("../data/fapar_global_modis_05d_yr.tif"); %#ok<*GTRED> 
fapar_sim_multi = geotiffread("../data/fapar_global_plmodel_05d_yr.tif");

pVal = 0.10;                     % Significance threshold for trend masking
[fapar_trend_upscale, fapar_pvalue_upscale, fapar_upscale_mean] = cal_linear_trend(fapar_obs_multi, 'Ftest', pVal);
[fapar_trend_sim, fapar_pvalue_sim, fapar_sim_mean] = cal_linear_trend(fapar_sim_multi, 'Ftest', pVal);

% show the spatial map
nums = 200;
options.range_trend = [-.3, .7];
CT_All = cbrewer_hint('div', 'BrBG', nums);
CT = CT_All([(nums/2*0.4+1):(nums/2*0.7), (nums/2*0.2+101):(nums/2*0.9+101)], :);

fig = figure('Color', [1 1 1]); %[output:829a30ff]
tiledlayout(2,1,"TileSpacing","tight","Padding","compact") %[output:829a30ff]
fig.Position(1) = fig.Position(1)*0.6; %[output:829a30ff]
fig.Position(3) = fig.Position(3)*0.8; %[output:829a30ff]
fig.Position(2) = fig.Position(2)*0.20; %[output:829a30ff]
fig.Position(4) = fig.Position(4)*0.9; %[output:829a30ff]

nexttile; %[output:829a30ff]
data_disp = fapar_trend_upscale .* 100;
data_disp(~roi_single_year) = nan;
fapar_pvalue_upscale(~roi_single_year) = nan;
geoshow_global(data_disp,'plot_pvalue','false','pvalue_matrix',fapar_pvalue_upscale,'plot_map_surface','true','plot_map_type','texturemap') %[output:829a30ff]
set(gca, 'Clim', options.range_trend) %[output:829a30ff]
set(gca,'FontSize',options.fontsize-3.5); %[output:829a30ff]
% text(options.text_position(1), options.text_position(2), 'MODIS','FontSize',12.5)

nexttile; %[output:829a30ff]
fapar_predicted_min_matrix_disp = fapar_trend_sim .* 100;
fapar_predicted_min_matrix_disp(~roi_single_year) = nan;
fapar_pvalue_sim(~roi_single_year) = nan;
geoshow_global(fapar_predicted_min_matrix_disp,'plot_pvalue','false','pvalue_matrix',fapar_pvalue_sim,'plot_map_surface','true','plot_map_type','texturemap'); %[output:829a30ff]
set(gca, 'Clim', options.range_trend) %[output:829a30ff]
set(gca,'FontSize',options.fontsize-3.5); %[output:829a30ff]
% text(options.text_position(1), options.text_position(2), 'PL model','FontSize',12.5)

% cb = colorbar(gca,"Location","southoutside","FontSize",10); cbarrow;
% title(cb, 'g C yr^{−1}')
box on; %[output:829a30ff]
colormap(cat(1,[1,1,1],CT)) %[output:829a30ff]
exportgraphics(fig, fullfile(path_figure_output, 'fAPARtrend_pvalue_nolabel.png'),"Resolution",600); %[output:829a30ff]

% Load PL trend decomposition where each band encodes a driver experiment and the full simulation
trend_green = geotiffread("../data/fapar_trend_global_plmodel_05d.tif");
trend_green_disp = trend_green;
trend_green_disp(~(abs(trend_green) > 0)) = nan;

driver_mode = "ctrl"; % Maintain native TRENDY contribution layers stored in the GeoTIFF
switch driver_mode
    case "diff"
        trend_green_contribute = trend_green_disp(:,:,end) - trend_green_disp;
    case "ctrl"
        trend_green_contribute = trend_green_disp;
    otherwise
        error("Unsupported driver_mode: %s", driver_mode);
end
str_save = char(driver_mode);

if ~isfield(options, "scale_trend")
    options.scale_trend = 100; % Express fractional greenness change as percentage per decade
end

if ~exist("cells_scenario", "var")
    cells_scenario = 1:size(trend_green_contribute, 3); % Match the number of driver layers embedded in the raster
end

%%
%% Driver attribution processing
[contribution_matrix, index_max] = max(abs(trend_green_contribute(:,:,1:5)), [], 3, "omitnan");
index_max(isnan(trend_green(:,:,end))) = nan;
[~, index_max_neg] = min(trend_green_contribute(:,:,1:5), [], 3, "omitnan");
[~, index_max_pos] = max(trend_green_contribute(:,:,1:5), [], 3, "omitnan");

index_max_final = index_max;

index_max_greening = index_max;
index_max_browning = index_max;

index_max_final(trend_green_contribute(:,:,end) > 0 & index_max==1) = 1; % + prec
index_max_final(trend_green_contribute(:,:,end) > 0 & index_max==3) = 2; % + PAR
index_max_final(trend_green_contribute(:,:,end) > 0 & index_max==5) = 2; % + TEMP
index_max_final(trend_green_contribute(:,:,end) > 0 & index_max==2) = 3; % + co2
index_max_final(trend_green_contribute(:,:,end) < 0 & index_max==3) = 4; % - PAR
index_max_final(trend_green_contribute(:,:,end) < 0 & index_max==4) = 5; % - VPD
index_max_final(trend_green_contribute(:,:,end) < 0 & index_max==5) = 6; % - TEMP
index_max_final(trend_green_contribute(:,:,end) < 0 & index_max==1) = 7; % - prec

fig_driver = figure('Color', [1 1 1]); %[output:20c43ecf]
tiledlayout(1,1,"TileSpacing","tight","Padding","compact") %[output:20c43ecf]

fig_driver.Position(1) = fig_driver.Position(1)*0.6; %[output:20c43ecf]
fig_driver.Position(3) = fig_driver.Position(3)*0.9; %[output:20c43ecf]
fig_driver.Position(2) = fig_driver.Position(2)*0.20; %[output:20c43ecf]
fig_driver.Position(4) = fig_driver.Position(4)*0.4; %[output:20c43ecf]
        
index_max_disp = index_max_final ;
index_max_disp(~(fapar_upscale_mean>0 & roi_single_year) ) = nan;

geoshow_global(index_max_disp) %[output:20c43ecf]
set(gca,'FontSize',options.fontsize-4.7); %[output:20c43ecf]
cb = colorbar('FontSize',font_size-5); %[output:20c43ecf]
% cb.Location = 'southoutside';
cb.Location = 'eastoutside'; %[output:20c43ecf]
% cb.Position(4) = cb.Position(4)*0.6;

tickNames = {'+PREC', '+TEMP', '+CO_2', '-PAR', '-VPD', '-TEMP', '-PREC'};
nums = length(tickNames);
% CT = cbrewer('div', 'Spectral', nums);
% CT = cbrewer('qual', 'Set2', nums);
cb_paired = cbrewer_hint('qual', 'Paired', 12);

% Can we find some better colours for the third plot. Try to relate the
% colours for the variables, e.g. pale blue for –ve precip, dark blue for
% +precip, light red for –temp, dark red for +ve temp. I’ve put some
% possible colours here, but this might need a bit of experimenting
CT_disp = cb_paired([2, 8, 4, 9, 5, 7, 1],:);
% CT_disp = cb_paired([1, 7, 3, 10, 6, 8, 2],:); % reverse
% colormap(CT(nums/2:end,:))
caxis([0.5, nums+0.5]) %[output:20c43ecf]
% clim([0.5, nums+0.5])
color_list = [[0 0.4470 0.7410]; ... % blue
    [0.4660 0.6740 0.1880]; ... % green
    [0.9290 0.6940 0.1250]; ... % yellow
    [189,190,192]./256;... % grey [0.3000 0.3000 0.3000]; ... % grey
    [0.4940 0.1840 0.5560]; ... % purple

    [0.8500 0.3250 0.0980]; ... % orange
    cb_paired(1,:); ... % light blue

    % [0.6350 0.0780 0.1840]; ... % dark red
    ];
% set(gca, 'ylim',[-60,90])
colormap(CT_disp(1:end, :)) %[output:20c43ecf]
% colormap(color_list)
% colorbar
cb.Ticks = 1:nums; %[output:20c43ecf]
cb.TickLabels = tickNames; %[output:20c43ecf]
axis([-180 180 -60 90]) %[output:20c43ecf]
% grid on
box on %[output:20c43ecf]
exportgraphics(fig_driver, fullfile(path_figure_output, 'fAPARtrend_driver_attribution.png'),"Resolution",600); %[output:20c43ecf]
%%
% Purpose:
% - Panel figure to compare spatial patterns among cases (scaled).
nums = 200;
CT_All = cbrewer_hint('div', 'BrBG', nums);
cb_paired = CT_All([(nums/2*0.4+1):(nums/2*0.7), (nums/2*0.2+101):(nums/2*0.9+101)], :);

% Mask: vegetated natural regions (captures biomes with persistent canopy cover)
roi_compare = fapar_upscale_mean > 0 & roi_single_year;

% Canvas (7 = ALL; 1..5 = soilm, co2, par, vpd, temp)
logic.tiled_layout = true;
if logic.tiled_layout
    fig = figure('Color', [1 1 1]); %[output:0188858e]
    if numel(cells_scenario) == 7
        t = tiledlayout(3, 2, "TileSpacing", "tight", "Padding", "loose"); %[output:0188858e]
        fig.Position(1) = fig.Position(1)*0.6; %[output:0188858e]
        fig.Position(3) = fig.Position(3)*1.2; %[output:0188858e]
        fig.Position(2) = fig.Position(2)*0.20; %[output:0188858e]
        fig.Position(4) = fig.Position(4)*0.9; %[output:0188858e]
    else
        t = tiledlayout(3, 1, "TileSpacing", "tight", "Padding", "loose");
        fig.Position(3) = fig.Position(3)*0.7;
    end
end

if numel(cells_scenario) == 7
    tickNames = {'PREC', 'CO_2', 'PAR', 'VPD', 'TEMP',  'FAPAR', 'ALL'};
    % tickNames = {'降水', 'CO_2', '辐射', 'VPD', '气温',  '绿度', '模拟'};
elseif numel(cells_scenario) == 3
    tickNames = {'CLIM', 'CO_2', 'ALL'};
    % tickNames = {'气候', 'CO_2', '模拟'};
end

if numel(cells_scenario) == 7
    selectedIndices = [7, 1, 2, 3, 4, 5];
    for idx = 1:numel(selectedIndices)
        m = selectedIndices(idx);
        nexttile; %[output:0188858e]
        fapar_obs_disp = trend_green_contribute(:,:,m) * options.scale_trend;
        fapar_obs_disp(~roi_compare) = nan;
        geoshow_global(fapar_obs_disp, 'logic_show_ticks', 'false')
        set(gca, 'Clim', options.range_trend)
        set(gca,'FontSize',options.fontsize-3);
        colormap(cb_paired)
        text(options.text_position(1), options.text_position(2), strcat('', tickNames{m}, ''),'FontSize',13)
        % text(options.text_position(1), options.text_position(2), strcat('$\rm{', tickNames{m}, '}$'), "Interpreter", "latex")
    end
    colorbar(gca, 'eastoutside', 'FontSize', font_size, 'Position', [0.92, 0.17, 0.01, 0.7]); % %[output:0188858e]
    warning off; cbarrow; warning on; %[output:0188858e]
elseif numel(cells_scenario) == 3
    selectedIndices = [3, 1, 2];
    for idx = 1:numel(selectedIndices)
        m = selectedIndices(idx);
        nexttile;
        fapar_obs_disp = trend_green_contribute(:,:,m) * options.scale_trend;
        fapar_obs_disp(~roi_compare) = nan;
        geoshow_global(fapar_obs_disp, 'logic_show_ticks', 'false')
        set(gca, 'Clim', options.range_trend)
        set(gca,'FontSize',options.fontsize-3);
        colormap(cb_paired)
        text(options.text_position(1), options.text_position(2), strcat('', tickNames{m}, ''),'FontSize',13)
        % text(options.text_position(1), options.text_position(2), strcat('$\rm{', tickNames{m}, '}$'), "Interpreter", "latex")
    end
    
    colorbar(gca, 'eastoutside', 'FontSize', font_size, 'Position', [0.89, 0.17, 0.01, 0.7]); %
    warning off; cbarrow; warning on;
end

% export the trend series
exportgraphics(fig, fullfile(path_figure_output, ['FigS_Trend_Scenarios',str_save,'.png']), "Resolution", 600); %[output:0188858e]
%%
% Fig 6 Temporal trends in gross primary production (GPP, PgC yr−1).
% Predicted inter-annual changes and temporal trends in global GPP from the
% PL and TRENDY models. Solid lines represent annual values; dashed line
% indicate the linear regression trend. The uncertainty envelope is the
% standard deviation of the global GPP simulated by the TRENDY models. The
% counter-factual PL model experiment (A0) assumes no change in greenness
% over the past two decades, and thus isolates the contribution of A0 to
% increasing GPP.

Years = YearBgn:YearEnd;

fig_gpp = figure('Color',[1 1 1]); %[output:87e3e308]
fig_gpp.Position(3) = fig_gpp.Position(3)*0.8; %[output:87e3e308]
fig_gpp.Position(4) = fig_gpp.Position(4)*0.7; %[output:87e3e308]

cb_paired = [0.6510    0.8078    0.8902
    0.1216    0.4706    0.7059
    0.6980    0.8745    0.5412
    0.2000    0.6275    0.1725
    0.9843    0.6039    0.6000
    0.8902    0.1020    0.1098
    0.9922    0.7490    0.4353
    0.9990    0.4980         0
    0.7922    0.6980    0.8392
    0.4157    0.2392    0.6039
    0.9990    0.9990    0.6000
    0.6941    0.3490    0.1569];

nexttile; %[output:87e3e308]
set(gca,'FontSize',options.fontsize-3); %[output:87e3e308]

load(fullfile('../data/', ['trendy_param_output_', 'gpp', '.mat']));
load(fullfile('../data/', ['trendy_data_output_', 'gpp', '.mat']));
load(fullfile('../data/', ['gpp_global_pgc', '.mat']));
hold on %[output:87e3e308]

% options.method_gpp = 'pmodel vs. PL model';
options.method_gpp = 'trendy vs. PL model';
if strcmpi(options.method_gpp, 'trendy vs. PL model')
    % Not including DLEM,VISIT
    fig_shaded = shadedErrorBar(data_model.year(1,:), data_model.lai([1,2,4:13],:), {@mean,@std}, 'lineprops', {'LineStyle','-','LineWidth',2.4,'Color',[76,77,79]/255},'transparent',false,'patchSaturation',0.075); %[output:87e3e308]
    % fig_shaded = shadedErrorBar(data_model.year(1,:), data_model.lai(:,:), {@mean,@std}, 'lineprops', {'LineStyle','-','LineWidth',2.4,'Color',[76,77,79]/255},'transparent',false,'patchSaturation',0.075);
    fig(3) = fig_shaded.mainLine;

    line_color = cb_paired(2,:);
    % [stats1, b1, fig(1)] = timeSeriesPlotwithBreakYear(gpp_pg_fluxcom_annual, 2001:2019, 1900, "pointColor",line_color,"fitlineColor",line_color,"StatisDisp","off","StatisDispItem","slope","StatisLocation","northeast","lineColor",line_color,"linewidth",2.4, "logicRegLine","false");
    line_color = [0.4,0.4,0.4];
    [stats_obs, b_obs, fig(1), linear_model_obs] = timeSeriesPlotwithBreakYear(mean(data_model.lai([1,2,4:13],:),1), Years(2:end), 1900, "pointColor",line_color,"fitlineColor",line_color,"StatisDisp","off","StatisDispItem","slope","StatisLocation","northeast","lineColor",line_color,"linewidth",2.4, "logicRegLine","true","markersize",18,"fitlinewidth",1.4,"fitlinestyle","--"); %[output:87e3e308]
    line_color = cb_paired(6,:);
    [stats_sim, b_sim, fig(2), linear_model_sim] = timeSeriesPlotwithBreakYear(trend_series_vector_sim(2:end), Years(2:end), 1900, "pointColor",line_color,"fitlineColor",line_color,"StatisDisp","off","StatisDispItem","slope","StatisLocation","northeast","lineColor",line_color,"linewidth",2.4, "logicRegLine","true","logicScatter","true","fitlinewidth",1.4,"fitlinestyle","--"); %[output:87e3e308]
    line_color = cb_paired(2,:);
    [stats_ctr, b_ctr, fig(3), linear_model_ctr] = timeSeriesPlotwithBreakYear(trend_series_vector_sim_bgn(2:end), Years(2:end), 1900, "pointColor",line_color,"fitlineColor",line_color,"StatisDisp","off","StatisDispItem","slope","StatisLocation","northeast","lineColor",line_color,"linewidth",2.4, "logicRegLine","true","logicScatter","true","markersize",18,"fitlinewidth",1.4,"fitlinestyle","--"); %[output:87e3e308]

    % add legend of the data
    legend(fig, {['TRENDY', ': ', num2str(b_obs(2),'%.2f'),' PgC yr^{−2}'], ['PL model: ', num2str(b_sim(2),'%.2f'),' PgC yr^{−2}'], ['\it{A}\rm_{0}: ', num2str(b_ctr(2),'%.2f'),' PgC yr^{−2}']},"Box","off","Location", 'northwest',"FontSize",13); %[output:87e3e308]
elseif strcmpi(options.method_gpp, 'pmodel vs. PL model')
    [stats_obs, b_obs, fig(1), linear_model_obs] = timeSeriesPlotwithBreakYear(trend_series_vector_obs(2:end), Years(2:end), 1900, "pointColor",cb_pastel2(1,:),"lineColor",cb_set2(1,:),"fitlineColor",cb_set2(1,:),"StatisDisp","off","StatisDispItem","slope","StatisLocation","northeast","linewidth",2.4,"logicRegLine","true","markersize",18,"fitlinewidth",1.4,"fitlinestyle","--");
    line_color = cb_paired(2,:);
    [stats_ctr, b_ctr, fig(3), linear_model_sim] = timeSeriesPlotwithBreakYear(trend_series_vector_sim_bgn(2:end), Years(2:end), 1900, "pointColor",line_color,"fitlineColor",line_color,"StatisDisp","off","StatisDispItem","slope","StatisLocation","northeast","lineColor",line_color,"linewidth",2.4, "logicRegLine","true","logicScatter","false","fitlinewidth",1.4,"fitlinestyle","--");
    [stats_sim, b_sim, fig(2), linear_model_ctr] = timeSeriesPlotwithBreakYear(trend_series_vector_sim(2:end), Years(2:end), 1900, "pointColor",cb_paired(3,:),"lineColor",cb_paired(4,:),"fitlineColor",cb_paired(4,:),"StatisDisp","off","StatisDispItem","slope","StatisLocation","northeast","linewidth",2.4,"logicRegLine","true","markersize",18,"fitlinewidth",1.4,"fitlinestyle","--");

    % add legend of the data
    % legend(fig, {['Pmodel ', 'Trend = ', num2str(b2(2),'%.2f')], ['PL model Trend = ', num2str(b3(2),'%.2f')]},"Box","off","Location", 'northwest',"FontSize",10);
    legend(fig, {['Pmodel ', 'Trend = ', num2str(b_obs(2),'%.2f')], ['PL model Trend = ', num2str(b_sim(2),'%.2f')], ['PL model Control = ', num2str(b_ctr(2),'%.2f')]},"Box","off","Location", 'northwest',"FontSize",options.fontsize-3);
    legend("Position", [0.15,0.66,0.43,0.25])
end

% show the trend in GPP
% legend(fig, {['Upscaled Flux', '= ', num2str(b1(2),'%.2f')], ['Trendy ', 'Trend = ', num2str(b2(2),'%.2f')], ['PL model Trend = ', num2str(b3(2),'%.2f')], ['PL model Control = ', num2str(b4(2),'%.2f')]},"Box","off","Location", 'northwest',"FontSize",10);
[r,pvalue] = corr(trend_series_vector_sim, trend_series_vector_obs);
str=['\it{r}\rm = ',sprintf('%.2f',r), '', pvalue_star_convert(pvalue), ''];

hold off %[output:87e3e308]
% grid on

box on; %[output:87e3e308]
ax=gca;hold(ax,'on'); %[output:87e3e308]
ax.YLim=[115,145]; %[output:87e3e308]
% ax.LineWidth=1.2;
ax.Box='on';
ax.TickDir='in'; %[output:87e3e308]
ax.XMinorTick='on'; %[output:87e3e308]
ax.YMinorTick='on'; %[output:87e3e308]
ax.ZMinorTick='on'; %[output:87e3e308]
ax.XColor=[.3,.3,.3]; %[output:87e3e308]
ax.YColor=[.3,.3,.3]; %[output:87e3e308]
ax.ZColor=[.3,.3,.3]; %[output:87e3e308]
% ax.FontWeight='bold';
% ax.FontName='Cambria';
ax.FontSize=options.fontsize-3; %[output:87e3e308]
ax.GridLineStyle='--'; %[output:87e3e308]

xl = xlim;
yl = ylim;
switch 'southeast'
    case 'northwest'
        x_position = (xl(2) - xl(1))*0.06 + xl(1);
        y_position = (yl(2) - yl(1))*0.90 + yl(1);
    case 'northeast'
        x_position = (xl(2) - xl(1))*0.80 + xl(1);
        y_position = (yl(2) - yl(1))*0.92 + yl(1);
    case 'southwest'
        x_position = (xl(2) - xl(1))*0.06 + xl(1);
        y_position = (yl(2) - yl(1))*0.1 + yl(1);
    case 'southeast'
        x_position = (xl(2) - xl(1))*0.60 + xl(1);
        y_position = (yl(2) - yl(1))*0.1 + yl(1);
    otherwise
        x_position = (xl(2) - xl(1))*0.06 + xl(1);
        y_position = (yl(2) - yl(1))*0.9 + yl(1);
end

hold off %[output:87e3e308]
xlabel('Year','FontSize',options.fontsize) %[output:87e3e308]
ylabel('Global GPP (PgC yr^{−1})','FontSize',options.fontsize) %[output:87e3e308]
num_years = 19;
disp(['MODIS ', 'Trend = ', num2str(b_obs(2)*num_years,'%.2f'), '(', num2str(b_sim(2)*num_years,'%.2f'), ') ± ', num2str(linear_model_obs.Coefficients.SE(2)*num_years,'%.3f'), '(', num2str(linear_model_sim.Coefficients.SE(2)*num_years,'%.3f'),')']) %[output:99dcc8b6]
disp(['Simulated ', 'Trend = ', num2str(b_sim(2)*num_years,'%.2f'), '(', num2str(b_ctr(2)*num_years,'%.2f'), ') ± ', num2str(linear_model_sim.Coefficients.SE(2)*num_years,'%.3f'), '(', num2str(linear_model_ctr.Coefficients.SE(2)*num_years,'%.3f'),')']) %[output:99b69a00]
exportgraphics(fig_gpp, fullfile(path_figure_output, 'GPPtrend_series.png'),"Resolution",600); %[output:87e3e308]

